# sprite_data.py - Wizard's Cavern sprite data and rendering functions
#
# External module containing all sprite sheets, mappings, and rendering.
# Imported by the main game file to keep it manageable.
#
# Sheets: 16px cells (standard), 18px cells (Compendium),
#         32px cells (Gemini, Characters)
# Compendium sheet: 30 cols x 18 rows (540 sprites)
# Gemini sheet: 16 cols x 16 rows (256 inventory icons)
# Characters sheet: 16 cols x 16 rows (humanoid portraits / NPCs)
#
# ASCII only - no Unicode, emojis, or special characters.

# Per-sheet cell size override (default is 16).
_SHEET_CELL_SIZE = {
    'Compendium': 18,
    'Gemini': 32,
    'Characters': 32,
}

def _cell_size_for(sheet_key):
    return _SHEET_CELL_SIZE.get(sheet_key, 16)

